const base = env.get('SEERR_URL');
const key = env.get('SEERR_API_KEY');
if (!base) { node.error('SEERR_URL not set'); return null; }
if (!key) { node.error('SEERR_API_KEY not set'); return null; }
const { query, page } = msg.payload || {};
msg.url = `${base}/api/v1/search?query=${encodeURIComponent(query)}&page=${page || 1}`;
msg.method = 'GET';
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const statusLabel = s => ({ 1: 'unknown', 2: 'pending', 3: 'processing', 4: 'partial', 5: 'available' }[s] || 'not_requested');
const items = (msg.payload.results || []).map(r => ({
  id: r.id,
  mediaType: r.mediaType,
  title: r.title || r.name,
  year: (r.releaseDate || r.firstAirDate || '').slice(0, 4) || null,
  overview: (r.overview || '').slice(0, 200) || null,
  status: statusLabel(r.mediaInfo && r.mediaInfo.status),
  poster: r.posterPath ? `https://image.tmdb.org/t/p/w300${r.posterPath}` : null
}));
msg.payload = JSON.stringify({ totalResults: msg.payload.totalResults, page: msg.payload.page, totalPages: msg.payload.totalPages, results: items });
return msg;

const base = env.get('SEERR_URL');
const key = env.get('SEERR_API_KEY');
if (!base) { node.error('SEERR_URL not set'); return null; }
if (!key) { node.error('SEERR_API_KEY not set'); return null; }
const { mediaId, mediaType, seasons, is4k } = msg.payload || {};
const body = { mediaId, mediaType: mediaType.toUpperCase(), is4k: !!is4k };
if (mediaType === 'tv' && Array.isArray(seasons) && seasons.length > 0) body.seasons = seasons;
msg.url = `${base}/api/v1/request`;
msg.method = 'POST';
msg.headers = { 'X-Api-Key': key, 'Content-Type': 'application/json' };
msg.payload = body;
return msg;

const code = msg.statusCode;
if (code === 201) {
  const r = msg.payload || {};
  msg.payload = JSON.stringify({ success: true, requestId: r.id, status: r.status, mediaType: r.type });
} else if (code === 202) {
  msg.payload = JSON.stringify({ success: true, note: 'No new seasons available to request' });
} else if (code === 403) {
  msg.payload = JSON.stringify({ error: 'Permission denied, quota exceeded, or media is blocklisted' });
} else if (code === 409) {
  msg.payload = JSON.stringify({ error: 'Already requested' });
} else {
  msg.payload = JSON.stringify({ error: `HTTP ${code}` });
}
return msg;

const base = env.get('SEERR_URL');
const key = env.get('SEERR_API_KEY');
if (!base) { node.error('SEERR_URL not set'); return null; }
if (!key) { node.error('SEERR_API_KEY not set'); return null; }
const { filter, mediaType, take } = msg.payload || {};
let qs = `take=${take || 20}&skip=0&filter=${filter || 'all'}&sort=added&sortDirection=desc`;
if (mediaType) qs += `&mediaType=${mediaType}`;
msg.url = `${base}/api/v1/request?${qs}`;
msg.method = 'GET';
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const statusLabel = s => ({ 1: 'unknown', 2: 'pending', 3: 'processing', 4: 'partial', 5: 'available' }[s] || 'unknown');
const results = (msg.payload.results || []).map(r => {
  const media = r.media || {};
  return {
    id: r.id,
    mediaType: r.type,
    title: media.title || media.originalTitle || null,
    status: statusLabel(media.status),
    requestedBy: r.requestedBy ? (r.requestedBy.displayName || r.requestedBy.email) : null,
    createdAt: r.createdAt
  };
});
msg.payload = JSON.stringify({ total: msg.payload.pageInfo ? msg.payload.pageInfo.results : results.length, results });
return msg;

const base = env.get('SEERR_URL');
const key = env.get('SEERR_API_KEY');
if (!base) { node.error('SEERR_URL not set'); return null; }
if (!key) { node.error('SEERR_API_KEY not set'); return null; }
msg.url = `${base}/api/v1/request/count`;
msg.method = 'GET';
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const c = msg.payload || {};
msg.payload = JSON.stringify({ pending: c.pending, approved: c.approved, available: c.available, failed: c.failed, total: c.total });
return msg;

const base = env.get('SEERR_URL');
const key = env.get('SEERR_API_KEY');
if (!base) { node.error('SEERR_URL not set'); return null; }
if (!key) { node.error('SEERR_API_KEY not set'); return null; }
const { tmdbId } = msg.payload || {};
msg.url = `${base}/api/v1/tv/${tmdbId}`;
msg.method = 'GET';
msg.headers = { 'X-Api-Key': key };
return msg;

if (msg.statusCode >= 400) { msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` }); return msg; }
const d = msg.payload || {};
const statusLabel = s => ({ 1: 'unknown', 2: 'pending', 3: 'processing', 4: 'partial', 5: 'available' }[s] || 'not_requested');
const mediaSeasons = (d.mediaInfo && d.mediaInfo.seasons ? d.mediaInfo.seasons : []);
const seasons = (d.seasons || []).filter(s => s.seasonNumber > 0).map(s => {
  const ms = mediaSeasons.find(x => x.seasonNumber === s.seasonNumber);
  return { seasonNumber: s.seasonNumber, episodeCount: s.episodeCount, airDate: s.airDate || null, status: statusLabel(ms && ms.status) };
});
msg.payload = JSON.stringify({
  id: d.id,
  name: d.name,
  firstAirDate: d.firstAirDate || null,
  overview: (d.overview || '').slice(0, 300) || null,
  status: statusLabel(d.mediaInfo && d.mediaInfo.status),
  poster: d.posterPath ? `https://image.tmdb.org/t/p/w300${d.posterPath}` : null,
  seasons
});
return msg;

